const feedback = $('Read Feedback').all();
const interactions = $('Read Interactions').all();
const existingLearnings = $('Read Learnings').all();

const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString();
const recentFeedback = feedback.filter(f => (f.json.Timestamp || '') >= sevenDaysAgo);

if (recentFeedback.length === 0) {
  return [{ json: { skip: true, summary: 'No recent feedback to process.' } }];
}

const interactionMap = {};
for (const i of interactions) {
  interactionMap[i.json.InteractionID] = i.json;
}

const lowRated = recentFeedback.filter(f => parseInt(f.json.Rating || 5) <= 3);

if (lowRated.length === 0) {
  return [{ json: { skip: true, summary: `${recentFeedback.length} feedback items, all positive. No learnings needed.` } }];
}

let context = 'RECENT LOW-RATED INTERACTIONS:\n\n';
for (const fb of lowRated) {
  const interaction = interactionMap[fb.json.InteractionID] || {};
  context += `Project: ${fb.json.ProjectName}\n`;
  context += `User asked: ${interaction.UserMessage || 'unknown'}\n`;
  context += `AI responded: ${(interaction.AIResponse || 'unknown').substring(0, 500)}\n`;
  if (interaction.ToolsUsed) context += `Tools used: ${interaction.ToolsUsed}\n`;
  if (interaction.DecisionTrace) context += `Decision trace:\n${(interaction.DecisionTrace || '').substring(0, 1000)}\n`;
  context += `Rating: ${fb.json.Rating}/5\n`;
  if (fb.json.Correction) context += `User correction: ${fb.json.Correction}\n`;
  context += '---\n';
}

context += '\nEXISTING LEARNINGS (already applied):\n';
for (const l of existingLearnings) {
  if (l.json.Active === 'TRUE') {
    context += `- [${l.json.ProjectName}] ${l.json.Learning}\n`;
  }
}

const avgRating = recentFeedback.reduce((sum, f) => sum + parseInt(f.json.Rating || 3), 0) / recentFeedback.length;

return [{ json: { skip: false, context, lowRatedCount: lowRated.length, avgRating: avgRating.toFixed(1) } }];

const text = $input.first().json.output || '';
const match = text.match(/\[[\s\S]*\]/);
if (!match) {
  return [{ json: { LearningID: 'none', ProjectName: 'global', Learning: 'No learnings extracted', Source: 'error', Active: 'FALSE', CreatedAt: new Date().toISOString().split('T')[0] } }];
}
try {
  const learnings = JSON.parse(match[0]);
  return learnings.map(l => ({ json: {
    LearningID: Date.now().toString() + Math.random().toString(36).substr(2, 4),
    ProjectName: l.project || 'global',
    Learning: l.learning,
    Source: 'feedback-synthesis',
    Active: 'FALSE',
    CreatedAt: new Date().toISOString().split('T')[0]
  }}));
} catch (e) {
  return [{ json: { LearningID: 'error', ProjectName: 'global', Learning: 'Parse error: ' + e.message, Source: 'error', Active: 'FALSE', CreatedAt: new Date().toISOString().split('T')[0] } }];
}
